								cursor: `worker-${index}`
							})),
							pageInfo: { hasNextPage: false, endCursor: null },
							totalCount: WORKERS.length
						},
						queueAndWorkersSummary: { maxCount: null }
					}
				})
			});
			return;
		}
		if (q.includes('ProviderTrend')) {
			const windowDays = Number(body.variables?.windowDays ?? 7);
